import{_ as r,C as c,o as t,c as s,an as o,b as n,w as d,a as i,E as l,ao as h}from"./chunks/framework.CTqRDTHW.js";const E=JSON.parse('{"title":"Feature: pgvector Migration + Observability Hardening","description":"","frontmatter":{},"headers":[],"relativePath":"011-vector-setup/spec.md","filePath":"011-vector-setup/spec.md","lastUpdated":1772533348000}'),p={name:"011-vector-setup/spec.md"};function m(u,e,g,k,v,b){const a=c("Mermaid");return t(),s("div",null,[e[1]||(e[1]=o('<h1 id="feature-pgvector-migration-observability-hardening" tabindex="-1">Feature: pgvector Migration + Observability Hardening <a class="header-anchor" href="#feature-pgvector-migration-observability-hardening" aria-label="Permalink to &quot;Feature: pgvector Migration + Observability Hardening&quot;">​</a></h1><blockquote><p><strong>Spec</strong>: 011-vector-setup <strong>Date</strong>: 2026-03-02 <strong>Status</strong>: Implemented <strong>Branch</strong>: 011-vector-setup</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Replace Qdrant (Cerebro / <code>arc-vector-db</code>) with pgvector — a PostgreSQL extension — so Sherlock stores conversation embeddings and history in a single Oracle (PostgreSQL) instance. The same feature hardens SigNoz/OTEL configuration for both Sherlock and Cortex, and adds proper Docker health checks throughout.</p><p><strong>pgvector is not a new service.</strong> It is a PostgreSQL extension installed into Oracle by switching the base image from <code>postgres:17-alpine</code> to <code>pgvector/pgvector:17-alpine</code>. The connection string, host, port, and credentials are unchanged.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Impact</th></tr></thead><tbody><tr><td>Dual-store complexity (Qdrant + PostgreSQL)</td><td>Two services to operate, two health checks, two failure modes</td></tr><tr><td>Qdrant adds ~400 MB to the <code>think</code> profile</td><td>Heavier dev startup with no benefit over pgvector for our scale</td></tr><tr><td>OTEL instrumentation is minimal in Sherlock and absent in Cortex</td><td>SigNoz shows no service data; distributed traces are incomplete</td></tr><tr><td>No Docker <code>healthcheck:</code> blocks on reasoner or persistence</td><td>Compose <code>depends_on</code> with no readiness signal is unreliable</td></tr></tbody></table><h2 id="target-modules" tabindex="-1">Target Modules <a class="header-anchor" href="#target-modules" aria-label="Permalink to &quot;Target Modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Path</th><th>Impact</th></tr></thead><tbody><tr><td>Persistence (Oracle)</td><td><code>services/persistence/</code></td><td>Image upgrade + init SQL</td></tr><tr><td>Reasoner (Sherlock)</td><td><code>services/reasoner/</code></td><td>pgvector migration + OTEL hardening</td></tr><tr><td>Cortex</td><td><code>services/cortex/</code></td><td>OTEL env vars only — no code changes</td></tr><tr><td>Platform profiles</td><td><code>services/profiles.yaml</code></td><td>Remove <code>vector-db</code> from <code>think</code></td></tr></tbody></table><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2>',10)),(t(),n(h,null,{default:d(()=>[l(a,{id:"mermaid-133",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20Before%0A%20%20%20%20%20%20%20%20SH1%5BSherlock%5D%20--%3E%7Cvector%20search%7C%20QD%5B(Qdrant%5Cnarc-vector-db%5Cn%3A6333)%5D%0A%20%20%20%20%20%20%20%20SH1%20--%3E%7Chistory%7C%20PG1%5B(PostgreSQL%5Cnarc-sql-db%5Cn%3A5432)%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20After%0A%20%20%20%20%20%20%20%20SH2%5BSherlock%5D%20--%3E%7Cvector%20search%5Cn%2B%20history%7C%20PG2%5B(PostgreSQL%20%2B%20pgvector%5Cnarc-sql-db%5Cn%3A5432)%5D%0A%20%20%20%20end%0A"})]),fallback:d(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o(`<h3 id="connection-model" tabindex="-1">Connection Model <a class="header-anchor" href="#connection-model" aria-label="Permalink to &quot;Connection Model&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Unchanged connection string</span></span>
<span class="line"><span>postgresql+asyncpg://arc:arc@arc-sql-db:5432/arc</span></span>
<span class="line"><span></span></span>
<span class="line"><span># New column on sherlock.conversations</span></span>
<span class="line"><span>ALTER TABLE sherlock.conversations ADD COLUMN embedding vector(384);</span></span>
<span class="line"><span></span></span>
<span class="line"><span># HNSW index for fast cosine search</span></span>
<span class="line"><span>CREATE INDEX ON sherlock.conversations USING hnsw (embedding vector_cosine_ops);</span></span></code></pre></div><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="r1-—-pgvector-extension" tabindex="-1">R1 — pgvector Extension <a class="header-anchor" href="#r1-—-pgvector-extension" aria-label="Permalink to &quot;R1 — pgvector Extension&quot;">​</a></h3><ul><li>The Oracle (<code>arc-sql-db</code>) image MUST use <code>pgvector/pgvector:17-alpine</code> as base</li><li><code>CREATE EXTENSION IF NOT EXISTS vector;</code> MUST run on first boot via <code>initdb/</code></li><li>The <code>vector-db</code> service MUST be removed from the <code>think</code> profile</li></ul><h3 id="r2-—-sherlock-memory-rewrite" tabindex="-1">R2 — Sherlock Memory Rewrite <a class="header-anchor" href="#r2-—-sherlock-memory-rewrite" aria-label="Permalink to &quot;R2 — Sherlock Memory Rewrite&quot;">​</a></h3><ul><li><code>SherlockMemory</code> MUST remove all Qdrant client code</li><li><code>SherlockMemory.save()</code> MUST write embedding + content to a single PostgreSQL row</li><li><code>SherlockMemory.search()</code> MUST query by cosine distance (<code>&lt;=&gt;</code> operator) with <code>user_id</code> filter</li><li>The <code>sherlock.conversations</code> table MUST gain an <code>embedding vector(384)</code> column</li><li>A HNSW index on the <code>embedding</code> column MUST be created on <code>init()</code></li><li><code>SherlockMemory.health_check()</code> MUST return <code>{&quot;postgres&quot;: bool}</code> (Qdrant key removed)</li></ul><h3 id="r3-—-config-cleanup" tabindex="-1">R3 — Config Cleanup <a class="header-anchor" href="#r3-—-config-cleanup" aria-label="Permalink to &quot;R3 — Config Cleanup&quot;">​</a></h3><ul><li>Settings <code>qdrant_host</code>, <code>qdrant_port</code>, <code>qdrant_collection</code> MUST be removed from <code>config.py</code></li><li><code>qdrant-client&gt;=1.9</code> MUST be removed from <code>pyproject.toml</code></li><li><code>pgvector&gt;=0.3.0</code> MUST be added to <code>pyproject.toml</code></li><li>All <code>SHERLOCK_QDRANT_*</code> env vars MUST be removed from <code>docker-compose.yml</code></li></ul><h3 id="r4-—-health-checks" tabindex="-1">R4 — Health Checks <a class="header-anchor" href="#r4-—-health-checks" aria-label="Permalink to &quot;R4 — Health Checks&quot;">​</a></h3><p><strong>Docker <code>healthcheck:</code> blocks</strong> (currently absent on both services):</p><table tabindex="0"><thead><tr><th>Service</th><th>Test command</th><th>Interval</th><th>Retries</th><th>Start period</th></tr></thead><tbody><tr><td><code>arc-sherlock</code></td><td><code>wget -qO- http://localhost:8000/health</code></td><td>15s</td><td>5</td><td>60s</td></tr><tr><td><code>arc-sql-db</code></td><td><code>pg_isready -U arc</code></td><td>10s</td><td>5</td><td>30s</td></tr></tbody></table><p><strong>API</strong> — <code>/health/deep</code> response MUST no longer include <code>qdrant</code> key:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ok&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.1.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;components&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;postgres&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;nats&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="r5-—-signoz-otel-configuration" tabindex="-1">R5 — SigNoz / OTEL Configuration <a class="header-anchor" href="#r5-—-signoz-otel-configuration" aria-label="Permalink to &quot;R5 — SigNoz / OTEL Configuration&quot;">​</a></h3><p>All standard OTEL env vars MUST be set in <code>docker-compose.yml</code> for Sherlock and Cortex so SigNoz auto-populates service metadata, environment, and namespace filters.</p><table tabindex="0"><thead><tr><th>Env Var</th><th>Value</th><th>Purpose</th></tr></thead><tbody><tr><td><code>OTEL_SERVICE_NAME</code></td><td><code>arc-sherlock</code> / <code>arc-cortex</code></td><td>Service identity in SigNoz</td></tr><tr><td><code>OTEL_SERVICE_VERSION</code></td><td><code>0.1.0</code></td><td>Version tag on spans</td></tr><tr><td><code>OTEL_DEPLOYMENT_ENVIRONMENT</code></td><td><code>development</code></td><td>SigNoz environment filter</td></tr><tr><td><code>OTEL_RESOURCE_ATTRIBUTES</code></td><td><code>service.namespace=arc-platform,...</code></td><td>Namespace grouping</td></tr><tr><td><code>OTEL_EXPORTER_OTLP_ENDPOINT</code></td><td><code>http://arc-friday-collector:4317</code></td><td>Collector endpoint</td></tr><tr><td><code>OTEL_EXPORTER_OTLP_PROTOCOL</code></td><td><code>grpc</code></td><td>Transport protocol</td></tr><tr><td><code>OTEL_TRACES_SAMPLER</code></td><td><code>always_on</code></td><td>100% sampling in dev</td></tr><tr><td><code>OTEL_PROPAGATORS</code></td><td><code>tracecontext,baggage</code></td><td>W3C trace propagation</td></tr><tr><td><code>OTEL_LOG_LEVEL</code></td><td><code>warn</code></td><td>Suppress SDK noise</td></tr></tbody></table><p>For Cortex (Go): these env vars are consumed by the Go OTEL SDK directly — no code changes. For Sherlock (Python): <code>OTEL_EXPORTER_OTLP_ENDPOINT</code> already mapped in <code>config.py</code>; remaining vars are standard and auto-consumed by the OTEL Python SDK.</p><h3 id="r6-—-tests" tabindex="-1">R6 — Tests <a class="header-anchor" href="#r6-—-tests" aria-label="Permalink to &quot;R6 — Tests&quot;">​</a></h3><ul><li>All Qdrant mocks in <code>test_memory.py</code> MUST be replaced with SQLAlchemy async mocks</li><li><code>health_check()</code> tests MUST verify <code>{&quot;postgres&quot;: bool}</code> shape (no <code>qdrant</code> key)</li><li>Existing 40-test suite MUST remain green</li></ul><h3 id="r7-—-contracts-docs" tabindex="-1">R7 — Contracts + Docs <a class="header-anchor" href="#r7-—-contracts-docs" aria-label="Permalink to &quot;R7 — Contracts + Docs&quot;">​</a></h3><ul><li><code>contracts/openapi.yaml</code>: <code>/health/deep</code> response schema updated (remove <code>qdrant</code> property)</li><li><code>services/reasoner/service.yaml</code>: remove <code>vector-db</code> from <code>depends_on</code>, update description</li><li><code>services/reasoner/service.yaml</code>: add <code>healthcheck</code> block</li></ul><h2 id="what-breaks-—-full-inventory" tabindex="-1">What Breaks — Full Inventory <a class="header-anchor" href="#what-breaks-—-full-inventory" aria-label="Permalink to &quot;What Breaks — Full Inventory&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Location</th><th>Break</th><th>Fix</th></tr></thead><tbody><tr><td><code>memory.py</code></td><td><code>qdrant_client</code> import</td><td>Remove — replace with pgvector</td></tr><tr><td><code>memory.py</code></td><td><code>_init_qdrant()</code></td><td>Remove — replaced by SQL DDL in <code>init()</code></td></tr><tr><td><code>memory.py</code></td><td><code>AsyncQdrantClient.search()</code></td><td>Replace with SQL cosine distance query</td></tr><tr><td><code>memory.py</code></td><td><code>AsyncQdrantClient.upsert()</code></td><td>Replace with SQLAlchemy <code>session.add()</code></td></tr><tr><td><code>memory.py</code></td><td><code>health_check()</code> qdrant branch</td><td>Remove — single postgres check</td></tr><tr><td><code>config.py</code></td><td><code>qdrant_host/port/collection</code> fields</td><td>Delete all three</td></tr><tr><td><code>pyproject.toml</code></td><td><code>qdrant-client&gt;=1.9</code></td><td>Remove</td></tr><tr><td><code>docker-compose.yml</code></td><td><code>SHERLOCK_QDRANT_HOST</code>, <code>SHERLOCK_QDRANT_PORT</code></td><td>Remove</td></tr><tr><td><code>main.py</code></td><td><code>&quot;qdrant&quot;: dep_health.get(&quot;qdrant&quot;, False)</code></td><td>Remove line</td></tr><tr><td><code>main.py</code></td><td><code>DeepHealthResponse</code> components</td><td>Now only <code>postgres</code> + <code>nats</code></td></tr><tr><td><code>service.yaml</code></td><td><code>depends_on: vector-db</code></td><td>Remove entry</td></tr><tr><td><code>service.yaml</code></td><td>description mentions Qdrant</td><td>Update text</td></tr><tr><td><code>profiles.yaml</code></td><td><code>vector-db</code> in <code>think</code></td><td>Remove entry</td></tr><tr><td><code>test_memory.py</code></td><td>All <code>AsyncQdrantClient</code> mocks</td><td>Replace with SQLAlchemy mocks</td></tr><tr><td><code>contracts/openapi.yaml</code></td><td><code>qdrant</code> in health deep schema</td><td>Remove property</td></tr></tbody></table><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li><code>services/vector/</code> — Cerebro/Qdrant service files remain untouched (other features may use it)</li><li>Cortex source code — no Go changes needed (OTEL via env vars only)</li><li>API v2 (<code>/v1/chat/completions</code>, streaming, history endpoints) — separate spec</li></ul>`,26))])}const S=r(p,[["render",m]]);export{E as __pageData,S as default};
